mapper.select:
SELECT d.id, d.building_id, d.dormitory_no, b.building_name, b.building_no, bd.dormitory_type, d.floor_number, d.room_usage_type, d.bed_capacity, d.room_type, CASE d.room_type WHEN 1 THEN '四人间' WHEN 2 THEN '六人间' WHEN 3 THEN '八人间' ELSE '未知' END as room_type_name, d.gender_type, CASE d.gender_type WHEN 1 THEN '男生宿舍' WHEN 2 THEN '女生宿舍' WHEN 3 THEN '混合宿舍' ELSE '未知' END as gender_type_name, d.bed_count as max_capacity, d.occupied_beds as current_count, d.occupied_beds, d.status, CASE d.status WHEN 1 THEN '正常' WHEN 2 THEN '维修' WHEN 3 THEN '停用' ELSE '未知' END as status_name, d.created_at, d.updated_at FROM dormitories d LEFT JOIN buildings b ON d.building_id = b.id AND b.deleted = 0 LEFT JOIN building_dormitories bd ON d.building_id = bd.building_id WHERE d.deleted = 0
AND d.dormitory_no LIKE CONCAT('%', #{req.dormitoryNo}, '%')
AND d.building_id = #{req.buildingId}
AND b.building_name LIKE CONCAT('%', #{req.buildingName}, '%')
AND d.floor_number = #{req.floorNumber}
AND d.room_type = #{req.roomType}
AND d.gender_type = #{req.genderType}
AND d.status = #{req.status}
AND d.building_id IN #{bid}
AND EXISTS ( SELECT 1 FROM student_dormitory sd INNER JOIN students s ON sd.student_id = s.id WHERE sd.dormitory_id = d.id AND s.class_id IN #{cid} AND sd.deleted = 0 AND s.deleted = 0 )
ORDER BY b.building_name ASC, d.floor_number ASC, d.dormitory_no ASC ORDER BY b.building_name DESC, d.floor_number ASC, d.dormitory_no ASC
ORDER BY d.dormitory_no ASC ORDER BY d.dormitory_no DESC
ORDER BY d.created_at ASC ORDER BY d.created_at DESC

SELECT COUNT(*)
FROM dormitories
WHERE building_id = #{buildingId}
AND dormitory_no = #{dormitoryNo}
AND deleted = 0

    AND id != #{excludeId}

SELECT d.id, d.building_id, d.dormitory_no, b.building_name, b.building_no, d.floor_number, d.room_type, CASE d.room_type WHEN 1 THEN '四人间' WHEN 2 THEN '六人间' WHEN 3 THEN '八人间' ELSE '未知' END as room_type_name, d.gender_type, CASE d.gender_type WHEN 1 THEN '男生宿舍' WHEN 2 THEN '女生宿舍' WHEN 3 THEN '混合宿舍' ELSE '未知' END as gender_type_name, d.bed_count as max_capacity, d.occupied_beds as current_count, d.status, CASE d.status WHEN 1 THEN '正常' WHEN 0 THEN '停用' ELSE '未知' END as status_name, d.created_at, d.updated_at FROM dormitories d LEFT JOIN buildings b ON d.building_id = b.id AND b.deleted = 0 WHERE d.deleted = 0 AND d.status = 1 AND d.occupied_beds < d.bed_count
AND d.gender_type = #{genderType}
ORDER BY b.building_name ASC, d.floor_number ASC
